export const One=()=>{
    // let style1={
    //     color:"orange",
    //     textAlign:"center"
    // }
    return <h2 id="one" style={{color:"blue",textAlign:"center"}}>I'm from Arrow one</h2>
}
export const Two=()=>{
    // let style2={
    //     width:"300px",
    //     background:"red"
    // }
    return <h2 id="two" style={{width:"350px"}}>I'm from Arrow Two</h2>
}
export const Three=()=>{
    // let style3={
    //     color:"violet"
    // }
    return <h2 id="three" style={{marginLeft:"100px",width:"400px"}}> I'm from Arrow Three</h2>
}
export const Four=()=>{
    let style4={
        width:"200px",
        background:"pink"
    }
    return <h2 id="four" style={style4}>  I'm from Arrow Four</h2>
}
export const Five=()=>{
    return <h2 id="five">I'm from Arrow Five</h2>
}
